def _load_embedded_module(name: str, source: str) -> types.ModuleType:
    full_name = f"athena.{name}"
    module = types.ModuleType(full_name)
    module.__file__ = f"{__file__}/athena/{name}.py"
    module.__package__ = "athena"
    sys.modules[full_name] = module
    setattr(package, name, module)
    exec(compile(source, module.__file__, "exec"), module.__dict__)
    return module


for _name, _source in MODULE_SOURCES.items():
    _load_embedded_module(_name, _source)


if __name__ == "__main__":
    from athena.main import main

    main()
